INSERT INTO items (id, category_id, sort_order, sort_key, time_value, title, subtitle, teaser, cover_path, card_info_json, detail_json, created_at, updated_at) VALUES ('movies-2602-demo', 'movies', 1, 2602, '26.02', '白色圣诞节', 'White Christmas', '冷感、悬念和圣诞氛围叠在一起的一集短篇。', '/assets/thumbs/media-a.svg', '[{"label":"类型","value":"短剧 / 科幻 / 特别篇"},{"label":"观看时间","value":"26.02"},{"label":"产地","value":"英国"},{"label":"主题","value":"数字意识，惩罚，节日反差"}]', '{"intro":"公开版示例卡片：用来演示影视条目的信息结构、排序和详情弹层。","review":"适合作为卡片站里那种一眼就能记住气质的条目。","gallery":[]}', '2026-04-06T00:00:00.000Z', '2026-04-06T00:00:00.000Z');
