INSERT INTO categories (id, title, english_title, summary, accent, sort_order, field_labels_json, time_field_label) VALUES ('places', '旅游', 'Travel Notes', '公开版只保留一张云南旅行卡片。', '#4f7b57', 3, '["事件","城市","时间","印象"]', '时间');
INSERT INTO items (id, category_id, sort_order, sort_key, time_value, title, subtitle, teaser, cover_path, card_info_json, detail_json, created_at, updated_at) VALUES ('places-2508-demo', 'places', 1, 2508, '25.08', '云南旅行', 'Yunnan Trip', '把私人旅行分类脱敏后，只保留一张公开演示卡。', '/assets/thumbs/travel-yunnan.svg', '[{"label":"事件","value":"旅行"},{"label":"城市","value":"云南"},{"label":"时间","value":"25.08"},{"label":"印象","value":"山景，慢节奏，晴空"}]', '{"intro":"这是公开版里唯一保留的旅游类条目，用来说明如何把私人站点里的现实生活内容裁剪成可公开的演示数据。","review":"第三栏不再出现生日、演唱会或私人事件，只保留一张纯旅行示例。","gallery":[{"src":"/assets/gallery/travel-yunnan-1.svg","caption":"云南旅行 · 第 1 张图","alt":"云南旅行 详情图 1"},{"src":"/assets/gallery/travel-yunnan-2.svg","caption":"云南旅行 · 第 2 张图","alt":"云南旅行 详情图 2"},{"src":"/assets/gallery/travel-yunnan-3.svg","caption":"云南旅行 · 第 3 张图","alt":"云南旅行 详情图 3"}]}', '2026-04-06T00:00:00.000Z', '2026-04-06T00:00:00.000Z');
